/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return -1;
    }

    // Step 1: Calculate Prefix Maximums (LMax)
    const lMax = new Array(n);
    lMax[0] = nums[0];
    for (let i = 1; i < n; i++) {
        lMax[i] = Math.max(lMax[i - 1], nums[i]);
    }

    // Step 2: Calculate Suffix Minimums (RMin)
    const rMin = new Array(n);
    rMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        rMin[i] = Math.min(rMin[i + 1], nums[i]);
    }

    // Step 3: Check stability for i = 0 to n-1
    for (let i = 0; i < n; i++) {
        // Unstable value U_i = max(nums[0..i]) - min(nums[i..n-1])
        const unstableValue = lMax[i] - rMin[i];

        if (unstableValue <= k) {
            return i; // Found the smallest stable index
        }
    }

    // If no stable index is found
    return -1;
}

